// Comprehensive Wine Tasting Notes Guide
// This document serves as a reference for identifying tasting notes in wine descriptions
// The system will parse wine descriptions looking for these specific terms
// If a note appears in one wine but not others in a comparison, it's a differentiating characteristic

export const WineTastingNotesGuide: { [key: string]: string } = {
  "acacia": "A delicate floral aroma reminiscent of acacia blossoms, which are sweet and lightly fragrant. In wine, acacia notes present as subtle, honeyed flower scents with a hint of fresh greenery. This aroma gives the impression of gentle white flowers and adds a soft floral character to the wine’s bouquet.",
  "acidic": "Describes a sour or tart taste in the wine, caused by higher acidity. An acidic wine makes your mouth water and can evoke sensations similar to biting into a lemon or green apple. It contributes freshness and vibrancy to the flavor, though if too acidic it may taste sharp or sour.",
  "aftertaste": "The flavor impressions that remain on the palate after you have swallowed the wine. Also called the finish, this describes the lingering tastes (such as fruit, oak, or spice) that you continue to perceive. A pleasant, long aftertaste (long finish) is usually a sign of quality, whereas a short or harsh aftertaste might be less desirable.",
  "alcoholic": "A term for a wine whose alcohol is out of balance, resulting in a noticeable burn or warmth. On the nose and palate it may smell or taste hot, like higher-proof spirits, and can give a slight sting in the back of the throat. An alcoholic wine often feels weighty and may overwhelm more delicate flavors.",
  "allspice": "A spice note in wine reminiscent of the sweet and warm aroma of allspice berries. It smells like a mix of clove, cinnamon, and nutmeg combined (much like the allspice seasoning). In wine tasting, allspice can present as a subtle baking spice complexity, adding depth to the aroma profile.",
  "almond": "A nutty aroma or flavor suggestive of almonds, which can be either raw and slightly bitter or sweet like marzipan. In some wines you may detect the scent of crushed almond skin or almond extract, giving a mild nuttiness. This note is especially common in certain whites and aged sparkling wines, contributing a subtle, sweet-nut nuance.",
  "angular": "Describes a wine with hard, sharp-feeling edges, often due to prominent acidity or tannin. An angular wine isn’t round or smooth – instead it presents its components in a pointed way, which can make the flavors feel less integrated. The taste comes across as brisk or austere, lacking a sense of softness on the palate.",
  "anise": "A spice note smelling of licorice or fennel seed, similar to the aroma of star anise. In wine, anise often appears as a faint sweet-herbal character, adding complexity. It might remind the taster of licorice candies or the subtle scent of fennel, contributing a mild spicy sweetness to the wine’s profile.",
  "apple": "The aroma of ripe, fresh apples (red or yellow apples). This note is like biting into a sweet, juicy apple – fruity and slightly sweet but with less tartness than green apple. Ripe apple notes add an orchard-fresh, wholesome fruit character to the wine’s profile.",
  "apricot": "The aroma of fresh, ripe apricots, a soft and sweet stone-fruit note. It smells like a juicy apricot at peak ripeness – fruity and floral with mild sweetness. Ripe apricot notes in wine lend a gentle, sunny fruit flavor often found in certain white wines (like Viognier or some dessert wines).",
  "aromatic": "A term indicating a wine with pronounced and intense aromas. An aromatic wine is very fragrant – when you smell it, a variety of scents (floral, fruity, spicy, etc.) are immediately evident and expressive. This quality is typical of certain grape varieties (like Gewürztraminer or Riesling) known for their strong, perfumed scent.",
  "ashy": "A smell or taste reminiscent of ash or soot, as if from a fireplace. An ashy note can make a wine’s aroma seem dry or smoky, like extinguished charcoal or cigarette ash. This character might come from heavy toasting of barrels or smoke influence and can add a rustic, smoky dimension to the wine’s profile.",
  "asparagus": "A green, vegetal aroma similar to fresh asparagus spears. This note is herbaceous and can be encountered in certain wines (notably some Sauvignon Blancs) where it gives a green vegetable scent. Depending on intensity, asparagus notes can add complexity (subtle fresh green nuance) or be considered off-putting if too pronounced (canned asparagus tone).",
  "astringent": "Causing a drying, puckering sensation on the palate, usually due to high tannins. An astringent wine makes your mouth feel rough or dry, similar to strong black tea or an unripe persimmon. This tactile feeling is not a flavor per se, but it affects the taste experience by making the wine seem firm, and if excessive can be unpleasantly bitter or drying.",
  "austere": "Describes a wine that is hard, unsmiling, or lacking obvious fruit sweetness – often due to high acid or tannin and minimal ripe fruit flavors. An austere wine feels strict on the palate: it may taste lean, with more mineral, acid, or bitter elements and very little plushness. Though it might soften with age or air, in its youth an austere wine comes across as reserved and not immediately generous in flavor.",
  "autolytic": "Refers to aromas derived from yeast breakdown (autolysis), often encountered in sparkling wines or wines aged on lees. An autolytic aroma is characterized by notes like bread dough, brioche, biscuit, or yeasty florals. It can give the wine a toasty, bakery-like scent (think of fresh bread or pastry), adding complexity beyond fruit characters.",
  "backward": "A term for a wine that is closed or not showing much of its character, often due to youth. A backward wine keeps its aromas and flavors hidden – you might detect structure (acid, tannin) more than fruit or bouquet. It suggests the wine needs more time (aging or air) to “come forward” and express its full range of flavors.",
  "bacon fat": "A rich, savory aroma reminiscent of smoked bacon or cured meats. In certain red wines (like Syrah/Shiraz), you might notice this meaty, smoky-fat scent intermingled with the fruit. It gives the wine a savory depth, as if there’s a faint note of crispy bacon or ham adding complexity to the nose and palate.",
  "baked": "A term indicating flavors of stewed or overripe fruit, as if the wine’s fruit component has been baked by heat. A baked wine might taste of cooked berries or prunes rather than fresh fruit, often accompanied by higher alcohol. It can suggest the grapes came from a very hot climate or were sun-exposed post-harvest, yielding a jammy, stewed fruit character with possibly a slight raisiny note.",
  "balanced": "Describes a wine in which all major components (fruit flavor, acidity, tannin, alcohol, sweetness, etc.) are in harmony. In a balanced wine, no single element sticks out harshly – for example, it doesn’t taste overly acidic, too alcoholic, or too tannic. The flavors and sensations complement each other, resulting in a smooth, cohesive tasting experience where the wine feels “just right” on the palate.",
  "balsamic": "An aromatic note that calls to mind balsamic vinegar or aromatic resins – a sweet-sour, woody scent. In wine, “balsamic” often refers to a complex mix of dried herbs, aged wood, and a slight vinegar-like sweetness (in a positive sense). It can give an impression of depth, like aged balsam or aromatic woods, adding intrigue with nuances of spice and tart sweetness (commonly found in aged Italian reds).",
  "banana": "A fruity aroma reminiscent of bananas, often specifically the smell of artificial banana candy or very ripe banana. This note is common in some young wines (like certain Beaujolais Nouveau) due to fermentation esters. It gives the wine a distinctly sweet, tropical fruit tone, sometimes described as smelling like banana Runts or banana taffy.",
  "band-aid": "A term for a particular medicinal/plastic aroma in wine, resembling the smell of adhesive bandages. It’s a kind of phenolic or chemical scent often associated with Brettanomyces yeast influence. The Band-Aid note comes across as an artificial, antiseptic smell (some say like a mix of plastic and iodine) and is usually considered a flaw when noticeable, as it can mask the wine’s fruit.",
  "barnyard": "An earthy, farm-like smell that can appear in some wines, often linked to Brettanomyces yeast. “Barnyard” evokes the aroma of a barn – think of hay, dirt, and a bit of animal musk or manure. While it sounds unpleasant, in small amounts it can add rustic complexity (like a faint horse stable or farm straw scent), though if strong it’s usually seen as a fault making the wine smell dirty or funky.",
  "basil": "A subtle herbal note reminiscent of fresh basil leaves. This aroma is green, slightly sweet, and peppery (basil is an aromatic herb used in cooking). In a wine context, a hint of basil might show up alongside other green herbal tones, contributing a fresh garden-herb character that can make the wine’s aroma profile more savory and complex.",
  "bay leaf": "An herbal aroma akin to dried bay laurel leaves. It comes across as a subtle woody herb scent with notes of menthol and spice. In wine, bay leaf nuances add a dried-herb complexity (often found in some reds), bringing to mind the smell of a spice cupboard or herbal tea and lending a savory, aromatic quality to the flavor.",
  "beeswax": "A waxy, honeycomb-like aroma that combines elements of honey, wax, and floral pollen. It smells a bit sweet and resinous, much like a honeycomb or a beeswax candle. In wines (especially some whites or wines affected by noble rot), beeswax notes contribute a rich, waxy-honey scent that adds depth and is often associated with texture as well.",
  "beetroot": "An earthy-sweet aroma similar to fresh red beets. This note smells a bit like soil and sweet root vegetables – an earthy, slightly rustic sweetness. When a wine has a beetroot note, it often gives a vegetal earthiness (sometimes noted in certain Pinot Noirs or other earthy reds) that can remind one of fresh beets or beet juice.",
  "big": "Describes a wine with bold, intense flavor or high body/alcohol that makes a strong impression. A “big” wine is full-bodied and rich; it might have high alcohol that gives warmth, and concentrated fruit or oak flavors that dominate the palate. Everything about it is ample – from aroma to taste, it’s powerful and not subtle.",
  "biscuit": "A subtle bready aroma reminiscent of plain biscuits or crackers. Often encountered in traditional method sparkling wines, it smells like a mix of baked dough and slight butteriness, though not sweet like a cookie. The biscuit note suggests a wine has spent time aging on yeast lees, imparting that toasty, cracker-like nuance that adds complexity beyond fruit notes.",
  "bitter": "A basic taste sensation typified by many tannic red wines or certain greens; it’s an unpleasant sharpness on the palate akin to unsweetened cocoa, black coffee, or citrus pith. In wine, bitterness often comes from tannins or unripe components, leaving a slight bitter aftertaste. While a hint of bitterness can contribute to structure, if it’s too pronounced the wine might taste harsh or astringent.",
  "black cherry": "A deep, dark cherry aroma, like the scent of sweet black cherries or black cherry juice. This note is richer and slightly sweeter than red cherry, often found in fuller-bodied red wines (like Cabernet Sauvignon or Syrah). Black cherry gives a wine a lush, dark fruit character – think of ripe Bing cherries – contributing to a sense of sweetness and depth in the fruit profile.",
  "black pepper": "A spicy aroma reminiscent of freshly cracked black peppercorns. It has a sharp, pungent spice scent that tingles the nose slightly, much like seasoning with pepper. In wine, a black pepper note is common in varieties like Syrah or Grüner Veltliner, adding a savory spice kick that complements the fruit with a peppery warmth on the nose and palate.",
  "black tea": "An aroma or taste analogous to brewed black tea or tea leaves. It carries a mild bitterness and leafy, dry quality, sometimes with a subtle woody or floral undertone like certain teas. In wine, a black tea note often comes from tannins or evolution of flavors (common in some aged reds), lending a slight astringency and refined, leafy nuance to the flavor profile.",
  "blackberry": "The scent of ripe blackberries – a dark berry aroma that is sweet and slightly tangy. It suggests juicy, wild blackberries bursting with flavor. This note is common in many red wines (like Zinfandel or Malbec), giving them a rich berry character; it adds to the perception of ripe, dark fruit sweetness in the wine.",
  "blackcurrant": "The distinctive aroma of blackcurrant berries, which is deep, dark, and sweet-tart. It’s often likened to the smell of crème de cassis (blackcurrant liqueur) – concentrated and rich. Blackcurrant notes (commonly found in Cabernet Sauvignon) give wine a powerful dark fruit character, somewhat sharp yet sweet, anchoring the fruit profile with a recognizable currant scent.",
  "blueberry": "A fruity aroma reminiscent of blueberries – sweet, with a slight tartness and a darker berry tone. In wine, blueberry notes often show up in certain red varietals (like Malbec or some Syrahs), contributing a plush, juicy berry character. It smells like ripe summer blueberries, adding to the perception of sweetness and round fruit flavor in the wine.",
  "body": "The sense of weight or fullness of the wine in your mouth. Body isn’t a flavor but a structural impression – a light-bodied wine feels thin and watery (like skim milk), a full-bodied wine feels heavy and rich (like whole milk). Wines with more alcohol, glycerol, or extract have more body, giving a mouth-coating, substantial feel, whereas lighter-bodied wines feel more delicate and airy on the palate.",
  "boiled cabbage": "A cooked vegetal aroma reminiscent of cabbage that has been boiled. This smell is sulfurous and cabbage-like (think of overcooked cruciferous vegetables). In wine, a boiled cabbage note is usually considered a flaw, often related to certain sulfur compounds or faults, giving the wine an unpleasant cooked veggie odor that detracts from cleaner aromas.",
  "boiled egg": "An aroma reminiscent of a hard-boiled egg or the sulfurous smell of egg yolk. This is a reductive note typically caused by sulfur compounds like hydrogen sulfide. In wine, a boiled egg smell is considered a fault – it presents as a mild rotten egg or eggy odor, indicating the wine might have had low oxygen during winemaking, and it’s generally undesirable.",
  "boxwood": "A pungent green aroma similar to crushed boxwood leaves or currant buds. It has a strong, catty, resinous smell (often likened to the scent of cat pee or tomcat urine in a more polite term). Boxwood is commonly associated with certain Sauvignon Blanc wines, giving them a sharp, green, musky-herbal note that can be intense and signature to that style.",
  "boysenberry": "A berry aroma resembling boysenberries, which are a cross of blackberry, raspberry, and loganberry. It smells like a mix of sweet dark berry and bright red berry notes – juicy and ripe. In wine, boysenberry can describe a composite berry impression (often in fruit-forward reds) where you sense both the richness of blackberry and the tartness of raspberry together, contributing to a lush fruitiness.",
  "brioche": "A rich bakery aroma reminiscent of buttery brioche bread. This note is bready, slightly sweet, and buttery, much like the scent of a freshly baked French brioche or pastry. It’s typically found in sparkling wines or certain whites aged on lees, where yeast contact imparts that toasty, bread-like fragrance, adding an elegant pastry nuance to the wine’s aroma.",
  "brooding": "Describes a wine with deep, dark aromas and flavors that feel intense but somewhat closed or mysterious. A brooding wine often has significant dark fruit, earth, or spice notes that suggest depth, yet it doesn’t reveal everything at once. On the nose and palate it comes across as serious, perhaps a bit reserved or “inward,” with an impression that there’s more to unfurl given time or aging.",
  "bubblegum": "A candied, sweet aroma similar to pink bubblegum. It carries a tutti-frutti or banana-strawberry candy scent that is distinctly confectionary. This note appears in some young wines made by carbonic maceration (like certain Beaujolais Nouveau), giving them a fun, candy-like fruitiness – as if one popped a piece of Bazooka or Hubba Bubba gum in the glass.",
  "burnt rubber": "A distinctive smell of scorched or burnt rubber, like a hot rubber hose or tire. In wine, this is usually considered a fault or at least an odd trait, often noted in certain wines as a result of specific winemaking issues or grape characteristics (famously sometimes in South African Pinotage). It gives a wine a charred, acrid rubbery note that can mask more pleasant aromas if strong.",
  "butterscotch": "A rich sweet aroma reminiscent of butterscotch candy or buttery caramel. It smells like melted brown sugar and butter combined – creamy, vanilla-like, and caramelized. In wine, butterscotch notes can develop in some oak-aged whites or aged dessert wines, lending a dessert-like profile (hints of toffee, caramel, butter) that adds to the wine’s complexity and sweetness impression.",
  "buttery": "Having an aroma or flavor evocative of butter or cream. A buttery wine often gives a smooth, rich mouthfeel and a scent like melted butter or buttered toast. This is commonly seen in some Chardonnay that has undergone malolactic fermentation, resulting in a creamy, dairy-like note. It makes the wine taste lush and round, with a flavor hinting at fresh butter or even butterscotch in some cases.",
  "gamey": "An aroma reminiscent of game or wild meats – slightly bloody, leathery, or like raw meat. A gamey note gives the wine a rustic, savory character, as if there’s a hint of smoked meat or cured sausage in the aroma. It’s often found in certain red wines like Rhône reds or Burgundy, contributing a wild, animal undertone that adds complexity (in moderation) to the fruit flavors.",
  "garlic": "A pungent aroma akin to raw garlic or garlic powder, sharp and sulfurous. In wine, a true garlic note is usually a flaw arising from certain sulfur compounds (mercaptans). It introduces an odd savory-acrid scent that can overwhelm the nose, reminiscent of chopped garlic – generally considered an off-aroma, as it detracts from fruit or floral notes.",
  "garrigue": "A term (borrowed from French) referring to the mix of wild resinous herbs found in Mediterranean scrubland – such as thyme, rosemary, lavender, and juniper. In wine, garrigue describes that fragrant herbal medley aroma. A wine with garrigue notes might smell like dried herbs, earthy shrub, and pine, giving a distinctly southern French countryside character – savory, herbal, and slightly floral all at once.",
  "geranium": "A pungent floral/herbal note resembling crushed geranium leaves or the scent of geranium flower oil. It tends to be a sharp, green floral smell. In wine, a geranium note is often a flaw caused by the wine additive sorbic acid, which can metabolize into a geranium-like aroma. It is generally considered unpleasant – like a mix of raw greens and faint flowers – and is not a typical positive descriptor.",
  "ginger": "A spice note smelling of fresh ginger root or ginger snaps. It has a warm, gently piquant aroma – lightly spicy, citrusy, and sweet. In some wines, especially those that are aged or botrytized, you might catch a ginger hint that adds zesty spice to the flavor profile. It can come across as fresh ginger’s subtle heat or candied ginger’s sweet spice, contributing liveliness and warmth.",
  "gooseberry": "A tart green fruit aroma strongly associated with Sauvignon Blanc wines. Gooseberry smells like a mix of sour grape, kiwi, and green tart berries – vibrant and zesty. In wine it presents as a sharp, tangy fruit note with a hint of grassiness. It gives an impression of green acidity and is a classic descriptor for New Zealand Sauvignon Blanc, lending a fresh but pungent fruit character.",
  "grapefruit": "A citrus aroma reminiscent of pink or yellow grapefruit, including its tangy juice and slight bitterness. This note is bright and zesty – smelling it in wine is like cutting open a fresh grapefruit. It brings both citrusy sweetness and pithy bitterness. Often found in white wines (like certain Sauvignon Blancs or Rieslings), grapefruit notes make the wine feel refreshing and crisp, with a bit of a bitter citrus kick on the finish.",
  "grapey": "A simple, direct aroma that literally smells like grapes or grape juice. It’s the scent you get from freshly crushed table grapes or grape candy – sweet, purple-fruit and straightforward. Describing a wine as grapey usually means it retains a lot of primary grape flavor (common in young wines or certain varieties like Muscat), giving the impression of biting into a sweet grape or drinking grape juice.",
  "graphite": "A mineral aroma similar to the smell of pencil lead (which is graphite) or a struck flint. It’s a clean, sharp stony scent with a hint of something metallic. In wines like Cabernet Sauvignon or Bordeaux blends, graphite often describes that refined pencil-shavings note on the nose. It lends a sense of minerality and sophistication to the aroma, as if you smelled a freshly sharpened pencil in the glass.",
  "grassy": "An aroma reminiscent of fresh-cut grass or hay. It’s a green, herbaceous scent that can make a wine smell like a spring meadow or a just-mowed lawn. Grassy notes are common in certain white wines (like some Sauvignon Blancs) and give a fresh, outdoorsy character. This can be pleasant in balance, adding freshness, though if too strong it might make the wine seem overly green or vegetal.",
  "green": "A general descriptor for flavors or aromas that suggest under-ripeness or plant-like characteristics. A “green” wine might have notes of bell pepper, grass, herbal leafiness, or unripe fruit. On the palate it can come across as slightly bitter or lacking sweetness, similar to biting into an unripe fruit or green vegetable. This term indicates the wine tastes a bit raw or undeveloped in its fruit profile.",
  "green bell pepper": "The distinct aroma of fresh green bell pepper (capsicum). It’s a crunchy, vegetal smell – think of sniffing a sliced bell pepper, which is herbaceous and slightly sweet. In wines, especially Cabernet Sauvignon, Merlot or Carménère, a green bell pepper note can appear due to compounds called pyrazines. It adds a savory, vegetal dimension to the wine; in small amounts it can be interesting, but if dominant it may indicate under-ripe grapes, making the wine smell very green.",
  "green tea": "A delicate aroma akin to brewed green tea or tea leaves. It’s lightly herbaceous, slightly nutty, and has a subtle dried grass character. In wine, a green tea note might show up in fine aged whites or light reds, contributing a nuanced leafy or tannic scent. It’s generally mild and adds complexity, reminiscent of the gentle, soothing smell of green tea rather than bold herbal tones.",
  "guava": "A tropical fruit aroma reminiscent of fresh guava pulp. It smells sweet, fragrant, and tropical – like a mix of pear, mango, and light citrus all in one. In wine, guava notes are often found in aromatic white varieties (or New World whites) giving an exotic, lush fruit character. This note makes the wine’s aroma profile feel tropical and ripe, as if a hint of guava nectar were present.",
  "gunflint": "A term for a specific smoky-mineral scent, like the smell of flint stone striking or gunpowder. It’s a steely, smoky rock aroma often noted in certain white wines (like flinty Chablis or Sauvignon Blanc from Sancerre). Gunflint gives a subtle smoke and stone character – imagine the faint spark smell from striking two flints together. It contributes to the perceived minerality of a wine, adding complexity beyond fruit aromas.",
  "hard": "Describes a wine that tastes overly tannic or acidic in an unyielding way, lacking softness. A hard wine strikes the palate with force – the tannins might feel aggressive and drying, or the acids too sharp. This makes the texture feel rough or the flavors unapproachable. Such a wine may need time to soften, but at the moment it comes off as rigid or stern, without enough fruit or roundness to balance those firm elements.",
  "hawthorn": "A delicate floral note similar to the blossoms of the hawthorn tree. Hawthorn flowers have a light, sweet, and slightly musky white-flower aroma. In wine, a hawthorn note often appears in certain white wines (and is commonly cited in French tasting) imparting a gentle hedgerow floral character. It enhances the bouquet with an airy spring-blossom scent that is subtle and pleasant.",
  "hay": "An aroma of dry hay or straw, giving a wine an earthy, sun-dried grass character. It’s reminiscent of walking into a barn with dried hay bales – slightly sweet, herbaceous, and rustic. Hay notes can be found in some white wines or lighter reds, contributing a countryside-like nuance. It can lend an impression of warmth and maturity, as if the fruit is intertwined with dried field grass.",
  "hazelnut": "A nutty aroma reminiscent of roasted hazelnuts. It’s toasty, slightly sweet-nutty, and can also recall the smell of praline or nougat. In wine, hazelnut notes often develop in whites aged in oak or on lees (such as some Chardonnays or Champagnes), giving a delicate nutty richness. It adds depth to the aroma, as if a hint of roasted nuts or hazelnut spread were present in the background.",
  "heavy": "Describes a wine that feels very full, weighty, or high in alcohol to the point of being out of balance. A heavy wine can come across as plodding or tiring on the palate – you might feel the alcohol warmth strongly or the flavors might be very dense and overbearing. It’s akin to a dish that is too rich. The wine lacks lift or freshness, instead giving an impression of thickness or excessive weight, which can dull the drinking experience.",
  "herbaceous": "Having aromas or flavors that are green and herb-like, reminiscent of herbs, leaves, or green vegetation. An herbaceous wine might smell of fresh-cut grass, basil, oregano, green pepper, or other leafy greens. This character often comes from compounds in certain grapes (like Sauvignon Blanc or Cabernet family varietals). Depending on intensity, herbaceous notes can add desirable freshness and complexity or, if dominant, make the wine seem vegetal or under-ripe.",
  "hibiscus": "A floral aroma similar to hibiscus flowers or hibiscus tea. It’s a soft, sweet floral with a slight berry-like and tart edge (as hibiscus used in tea has a cranberry-like aspect). In wine, hibiscus notes are not very common but might be found in some aromatic profiles, contributing a fragrant red-floral tone. It adds an exotic bloom character, as if a subtle waft of floral fruit tea or tropical flower is present.",
  "hollow": "Describes a wine that lacks mid-palate flavor or depth – it starts and finishes with some impression, but there’s an empty gap in the middle. When tasting a hollow wine, you might notice initial fruit or acid, then a notable absence of flavor in the center of your mouth, and then perhaps a bit of tannin or heat in the finish. It feels as though the wine has a hole in its flavor profile, making it seem less complete or satisfying.",
  "honey": "A sweet aroma reminiscent of honey or honeycomb. It evokes the scent of wildflower honey – floral, nectar-like, and richly sweet. In wine, honey notes are common in late-harvest or botrytized wines (like Sauternes or Riesling Auslese), but can also appear in aged whites. It lends a luxurious sweetness on the nose, even if the wine is dry. This note makes the bouquet feel warm and golden, as if a drizzle of honey were mixed in.",
  "honeysuckle": "A floral aroma akin to honeysuckle blossoms – sweet, nectar-like, and delicate. It smells like spring evenings: a soft, perfumed sweetness that isn’t overly heavy. In wine, honeysuckle is often noted in fragrant white varieties (like Viognier or some muscat-based wines), adding an enticing flower perfume. It contributes a fresh yet sweet floral character, much like sniffing a honeysuckle vine in bloom.",
  "horse blanket": "A rustic aroma often associated with Brettanomyces that smells like a well-worn leather saddle or a horse blanket. It’s an animalistic, sweaty odor with elements of leather, musk, and barnyard. In small amounts, some find it can add old-world complexity (a kind of rough, outdoorsy charm), but if strong it is usually considered a flaw. Essentially, it’s the smell of a sweaty horse tack room – a mix of dried sweat, leather, and animal – and can greatly overshadow fruit if prevalent.",
  "horse manure": "A pungent barnyard aroma that specifically recalls the smell of horse droppings or a manure pile. It’s an earthy, fecal smell – generally unwelcome in wine. This odor indicates a strong Brettanomyces influence or spoilage. While terms like “barnyard” might encompass mild touches of animal musk, horse manure is more intense and clearly off-putting, as it suggests the wine’s aroma has been overtaken by foul, farm waste-like scents.",
  "hot": "Describes the burning sensation on the palate from high alcohol. A hot wine makes your mouth and throat feel warm or even sting slightly, similar to a sip of spirit. This heat can overshadow flavors, giving a impression of peppery spice or solvent. When a wine is described as hot, it generally means the alcohol is not well integrated – you feel the alcohol disproportionately, which can detract from the overall balance and pleasure of the wine.",
  "incense": "A spicy, resinous aroma reminiscent of burning incense sticks (such as frankincense or myrrh). It has a sweet smoke, churchlike fragrance – think aromatic resins, sandalwood, and spice. In some full-bodied or aged wines, especially those with rich oak influence, you might detect an incense-like note. This gives the wine an exotic, smoky-sweet perfume, adding a layer of complexity that feels almost spiritual or meditative in character.",
  "iodine": "A briny, medicinal aroma similar to tincture of iodine or sea air. It’s a scent that hints at salt, metal, and medicine cabinet. In wine, iodine notes sometimes appear in very mature reds or certain terroir-specific wines (like some from coastal or volcanic soils). It can give a savory, almost bloody/mineral nuance (people also liken it to seashore or oyster shell). A touch of iodine can add intrigue, but too much might seem medicinal or odd.",
  "iris": "A delicate floral note akin to iris flowers. The aroma of iris (especially the orris root derived from it) is soft, powdery-floral with a slight earthy woodiness. In wine, an iris note would contribute a gentle, elegant floral perfume – not as overtly sweet as rose, nor as citrusy as orange blossom, but a refined floral hint. It’s not very common to identify specifically, but when present it elevates the fragrance with a classy floral tone.",
  "jalapeño": "A green, spicy aroma similar to the smell of a fresh cut jalapeño pepper (without necessarily the chili heat on the palate). It has a distinctive vegetal spice note – think green pepper with a slight kick. In wines, this can be noted in some Sauvignon Blancs or Cabernet Francs that have pronounced pyrazines, lending a peppery green chili character. It adds a fiery herbaceous touch to the aroma, though the wine itself isn’t “spicy” in terms of capsaicin heat.",
  "jammy": "Describes a wine with very ripe, sweet fruit flavors reminiscent of jam or preserves. A jammy wine is bursting with cooked-fruit sweetness – think strawberry jam, blackberry preserves, or plum compote. The fruit is intense and concentrated, often as a result of very ripe grapes or hot-climate growing conditions. While jammy notes can make a wine feel generous and fruit-forward, if overdone the wine may lack freshness or structure, coming off as simple or cloyingly fruity.",
  "jasmine": "A floral aroma akin to jasmine flowers. It’s a sweet, heady white-flower scent often associated with night-blooming jasmine – very fragrant and perfumed. In wine, jasmine notes can appear in aromatic whites or certain sweet wines, lending an exotic, floral elegance. It adds a lovely perfume element to the bouquet, as if a few jasmine petals were steeped in the wine, imparting their intense, flowery sweetness.",
  "kirsch": "The aroma of kirschwasser (a cherry brandy), essentially the scent of distilled cherries – powerful, sweet, and alcoholic cherry fragrance. Kirsch in wine tasting refers to a candied, spirit-like black cherry note. It often appears in descriptions of rich reds (like some Grenache-based wines or Barolo), where the cherry aroma is so ripe and concentrated it’s reminiscent of cherry liqueur. This note gives a combination of sweet dark cherry and a hint of almond/boozy warmth, adding depth to the fruit character.",
  "lavender": "A floral-herbal aroma reminiscent of lavender buds. It’s sweet, purple-floral but also slightly camphorous and herbal. In wine, lavender notes might be found in some Mediterranean reds or aromatic whites, contributing a Provence-like scent. The presence of lavender gives the wine a soothing yet vibrant floral character, as if a touch of lavender oil or dried lavender flowers were in the bouquet.",
  "lean": "Describes a wine that is light-bodied and lacks plushness, often with higher acidity and not much richness. A lean wine feels taut and maybe a bit thin – it emphasizes crispness or structure over ripe fruit. On the palate, it may come across as narrowly focused (perhaps more mineral or green notes, fewer sweet fruit flavors). While lean wines can be refreshing and elegant, if taken to an extreme they might seem undernourished or lacking flavor generosity.",
  "leather": "An aroma reminiscent of leather material – like an old leather jacket or a saddle. It’s a warm, earthy, somewhat animal scent with a bit of dryness. Leather notes commonly develop in aged red wines (like mature Rioja or Bordeaux) or wines with Brettanomyces influence. A touch of leather can add a sense of rustic warmth and complexity, giving the impression of old books or fine leather furniture integrated with the wine’s fruit.",
  "lemon": "A citrus aroma and flavor like that of a fresh lemon. It carries the zesty brightness and tang of lemon juice along with the fragrant quality of lemon peel. In wine, lemon notes contribute a lively, tart citrus character (common in many white wines, from Chablis to Riesling). It makes the wine feel crisp and refreshing – as if a squeeze of lemon were enhancing the flavors. Sometimes one might distinguish lemon zest (the aromatic, oily peel) versus lemon juice (the sour part); both aspects add to a wine’s vibrant acidity and aroma.",
  "lemongrass": "An aroma akin to fresh lemongrass, a citrusy herb used in Asian cuisine. It has a distinctive lemon-citrus scent with green herbal undertones. In wine tasting, lemongrass notes might appear in certain Sauvignon Blancs or other zesty whites, contributing a complex citrus-herbal character. It makes the wine’s aroma interesting by adding that tangy lemon plus light herbal grass combination, which comes off as both refreshing and exotic.",
  "licorice": "A note that resembles black licorice candy or anise licorice root. It’s sweet and herbal-spicy at the same time, with a recognizable aniseed fragrance. In wines, especially some Italian reds or Syrahs, a licorice note can emerge, giving a sweet-woody spice nuance. It deepens the flavor profile by adding that candied fennel flavor – a bit earthy, a bit sweet, and slightly bitter – much like the taste of a licorice twist.",
  "lilac": "A floral aroma similar to lilac blossoms. Lilacs have a sweet, enchanting springtime scent that is both floral and slightly powdery. In wine, lilac notes may be subtle but can appear in aromatic whites or light reds, imparting a gentle purple-flower fragrance. This adds a pretty, fragrant top note to the wine’s bouquet, as if a breeze of lilac from a garden is passing through the glass.",
  "lime": "A citrus aroma/taste reminiscent of fresh lime juice or lime zest. It has a sharp, tangy profile with a slightly floral-citrus peel aroma. Lime notes in wine (often in Rieslings, Sauvignon Blancs, or Australian Semillon) give a punchy citrus character that’s very vibrant. It contributes to high acidity perception – making the wine feel extra crisp – and leaves a refreshing, tart citrus impression similar to squeezing a lime wedge.",
  "linden": "A floral aroma of linden tree blossoms (often called lime blossom, though unrelated to the citrus fruit). Linden flowers smell sweet, green-floral, and somewhat honeyed. In wine, a linden blossom note imparts a gentle, spring-like floral character (common in some Rieslings or Loire whites). It’s an elegant, soft perfume suggesting a mix of flowers and faint honey, adding refinement to the aroma.",
  "lit match": "The distinctive smell right after striking a match – essentially a sulfurous, smoky note. In wine, a “lit match” aroma typically comes from a bit of free sulfur (sulfur dioxide) or certain reductive processes, and can be found in some Chardonnays or other wines that see controlled oxygen exposure. It smells slightly of burnt sulfur and flint. In small amounts, some tasters enjoy it as a nuance (referred to as struck match or gunflint, especially in Burgundian-style Chardonnay), but if too strong it can be acrid. It adds a flinty, smoky accent to the scent profile.",
  "lively": "Describes a wine that feels energetic on the palate, often thanks to good acidity or slight effervescence. A lively wine has a refreshing, spirited character – it makes your taste buds perk up. You might sense a crisp tang or a subtle fizz that gives a prickle. Overall, calling a wine lively means it comes across as fresh, vibrant, and full of life, rather than dull or heavy.",
  "lychee": "A tropical fruit aroma typical of lychee fruit, which is very fragrant and sweet. It’s like a combination of grapes and roses with a touch of melon – a unique perfumed fruit scent. Lychee is famously noted in Gewürztraminer and some Muscat wines, giving them an exotic, floral-fruit character. This aroma makes the wine stand out with a lush, almost perfumed sweetness, as if rosewater and pear were mixed together, contributing to a rich aromatic profile.",
  "mango": "A tropical fruit aroma reminiscent of ripe mango. It’s lush, sweet, and a bit musky, with a rich yellow-fruit scent. In wine, mango notes often appear in aromatic whites or sweet wines, adding an exotic, ripe fruit character. Smelling a mango note in wine is like catching the scent of a juicy, soft mango at peak ripeness – it imparts a sense of tropical richness and sweetness to the flavor profile.",
  "maple syrup": "A rich, sweet aroma similar to the scent of maple syrup. It has a caramelized sugar quality with woody undertones (since maple syrup comes from tree sap). In wine, a maple syrup note might emerge in certain heavily botrytized dessert wines or long-aged sweet wines, giving a deep caramel-sugar and slight smoky wood sweetness. It adds a decadent, dessert-like element to the bouquet – as if a hint of pancake syrup or burnt sugar were present.",
  "marmalade": "An aroma reminiscent of orange marmalade, which is a mix of sweet citrus and bitter orange peel. It carries candied orange notes with a hint of zest bitterness and sugar. In wine, marmalade is often noted in sweet or aged whites (especially those with botrytis) where citrus peel and honeyed sweetness combine. It imparts a complex citrus character – both fruity and slightly tangy-bitter – much like tasting orange jam with peel included.",
  "marzipan": "The sweet aroma of almond paste (marzipan), which smells like sugary almonds – nutty and confectionary. It’s a bit like sweet almond candy or almond extract. In wine, marzipan notes can be found in some sparkling wines or whites aged on lees, contributing a dessert-like nutty sweetness. It enriches the aroma with a patisserie quality (imagine an almond pastry or cake icing scent), adding to the wine’s complexity especially as it ages.",
  "mature": "Describes a wine that has reached a developed stage of its life, where primary fruitiness may have faded and more complex, secondary and tertiary notes have emerged. A mature wine often shows notes of dried fruits, nuts, earth, or leather that weren’t present when young. On the palate it tends to be smoother, with tannins softened. Saying a wine is mature implies it’s at or near its optimal drinking window, displaying harmonious, evolved flavors (as opposed to fresh, youthful ones).",
  "meaty": "An aroma or flavor that is reminiscent of raw or cooked meat. It can evoke the savoriness of cured meats, broth, or even the slight bloodiness of a rare steak. In some bold red wines (like Syrah or Mourvèdre), a meaty note adds a savory depth – you might feel as though there’s a hint of beef bouillon or charcuterie in the glass. This hearty characteristic rounds out the fruit with a robust, umami quality.",
  "mellow": "Describes a wine that is soft, smooth, and lacking any harsh edges. A mellow wine has gentle flavors – nothing jarring or overly acidic/tannic. It comes across as relaxed on the palate, often as a result of age or good balance. The term suggests an easy-drinking nature: the wine’s components have integrated, its intensity is moderate, and it gives a soothing, pleasant experience without challenging the senses.",
  "melon": "A fresh fruit note resembling the smell of melons, often honeydew or cantaloupe. It’s a mild, green-sweet aroma that is less sharp than citrus and not as overtly tropical as mango – more of a clean, dewy fruit scent. In wine, melon notes (like honeydew melon) frequently appear in lighter white wines (such as some Pinot Grigio or Chablis), providing a gentle fruitiness. This aroma makes the wine seem refreshing and approachable, with a hint of summer fruit softness.",
  "menthol": "An aroma akin to mentholated mint or eucalyptus – cooling, minty, and slightly medicinal. It’s the sort of nose-tingling fresh scent you get from menthol cough drops or a crushed eucalyptus leaf. In wines, menthol notes often appear in some Cabernet Sauvignon or Shiraz, contributing a cooling herbal lift. It can make the wine smell a bit like mint or camphor, adding complexity and a sense of freshness despite the wine’s richness.",
  "metallic": "A smell or taste that is reminiscent of metal or coins, like touching your tongue to iron or copper. It can also evoke the scent of blood (which is high in iron). In wine, a metallic note might present as a faint taste of iron or a tinny aroma. Sometimes it’s linked to high iron in soil or slight oxidation. In small amounts, it can add a mineral edge, but if strong it’s usually a flaw, making the wine taste a bit like metal or rust, which is generally unpleasant.",
  "mineral": "A broad term describing aromas/flavors that resemble rocks, wet stone, chalk, or other non-organic elements. A mineral note in wine isn’t fruity or herbal – it’s more like the smell of wet slate, limestone, flint, or even a saline, chalky tone. This can give a wine a sense of place (terroir), often noted in Old World wines. Minerality often comes across as a stony, earthy freshness – imagine sniffing a handful of river pebbles or limestone after rain. It adds complexity and is typically subtle, underlying the fruit with a steely or earthy foundation.",
  "mint": "An aroma of fresh mint leaves. It’s herbaceous, cool, and sweetly pungent, like smelling a crushed spearmint or peppermint leaf. In some wines (for instance, Coonawarra Cabernet or certain Chilean reds), a mint note can be present, lending a refreshing lift to the bouquet. It adds a cooling herbal character that can balance rich fruit, making the wine smell slightly green in a pleasant, invigorating way, as if garnished with a spring of mint.",
  "molasses": "A deep, sweet aroma similar to dark molasses or treacle – essentially a rich, brown-sugar syrup scent. It has notes of burnt sugar, toffee, and a bit of smoky bitterness. In wine, molasses notes might appear in very ripe, port-like wines or extremely concentrated sweet wines, giving a thick, sugarcane sweetness with a hint of char. It adds a sense of heaviness and richness, contributing to a dessert-like profile (imagine the scent of brown sugar caramelizing in a pan).",
  "monolithic": "Describes a wine that tastes one-dimensional, lacking complexity or development of flavors. A monolithic wine presents basically one dominant flavor (often fruit or oak) that carries through without variation. It doesn’t evolve much from start to finish on your palate. This term suggests the wine, while perhaps bold, is straightforward and somewhat simplistic – all its elements seem fused into a single block of flavor, without layers or nuance.",
  "mulberry": "A dark berry fruit note akin to mulberries, which taste like a cross between blackberry and grape with a slight floral edge. In wine terms, mulberry suggests a juicy, dark berry character that isn’t as tart as raspberry nor as sweet as ripe blackberry – something in between, often slightly plummy and rustic. This note might be found in some red wines from warm climates, contributing to the dark fruit spectrum with a unique berry tone. It adds to the wine’s fruitiness in a soft, rounded way.",
  "mushroom": "An earthy aroma reminiscent of fresh mushrooms or forest floor fungus. It has a damp, woodsy scent with a bit of savory earth. In wine, mushroom notes often develop with age (particularly in Pinot Noir or mature Champagne) or can indicate certain terroir. This adds an autumnal, truffle-like depth to the aroma. A touch of mushroom can make a wine smell more complex and aged – akin to the smell of a misty forest or a basket of wild mushrooms – and is generally a positive trait in aged fine wines.",
  "musky": "A descriptor for a subtle animalistic or perfumed aroma that is slightly sweet but also earthy or animal. Musky notes can be like the scent of musk perfume (which is derived from animal musk) – it’s a deep, body-like sweet odor. In wine, a musky note might come from very ripe grapes or certain aromatic varieties, giving a sensual, earthy-floral nuance. It can make the wine’s bouquet feel heavier or more exotic, but if overdone it might be perceived as funky or cloying.",
  "musty": "A damp, stale aroma often compared to wet cardboard, moldy basement, or a mildewed cloth. Musty indicates the wine likely has been affected by cork taint (TCA) or poor storage, and it smells like cardboard that got wet and grew mold – dull, dusty, and earthy in a bad way. This off-aroma drowns out fruit and is considered a fault. If a wine is musty, it’s like sniffing an old damp newspaper or a dank cellar, lacking freshness and appeal.",
  "nail polish remover": "A sharp, solvent-like aroma identical to acetone (the main chemical in many nail polish removers). It smells like a mix of artificial fruit and strong solvent/varnish. In wine, this indicates the presence of volatile acidity (particularly ethyl acetate) beyond the normal level. It’s generally a flaw if strong – the wine’s scent stings the nose a bit like sniffing actual nail polish remover. You might catch a whiff of something vaguely like glue or paint thinner combined with overripe fruit. In small doses it can add complexity, but if you distinctly smell nail polish remover, the wine is considered to have too much VA.",
  "nectarine": "A stone fruit aroma similar to that of a ripe nectarine (which is quite like peach but sometimes a bit more floral and tart). It smells of sweet, juicy orange-yellow flesh with a slight zesty skin note. In wine, nectarine notes (common in some Viogniers, Rieslings, or Chardonnays) give a luscious fruit character that’s in between peach and apricot. It adds to the wine’s fruit profile with a summery sweetness and a hint of citrusy lift.",
  "nervy": "Describes a wine high in acidity that’s exciting and edgy on the palate. A nervy wine has a certain tension – a brisk, electric feel that comes from pronounced acidity or minerality. It makes your palate sit up, almost on edge (in a good way), as if the wine is tightly wound. People often use “nervy” for young Rieslings or cool-climate wines where the brightness borders on being piercing, but also gives the wine a vivid, dynamic character.",
  "nettles": "An aroma of stinging nettles or nettle tea – green, herbal, and slightly sharp. It’s somewhat like crushed green leaves with a faint peppery edge. In wine, nettle notes are particularly associated with Sauvignon Blanc (especially from New Zealand or the Loire), contributing to the green spectrum of its aromas. It reinforces a wild, herbal freshness, as if a bunch of nettle or cut weeds were part of the bouquet, adding pungency and greenery.",
  "nutmeg": "A spice aroma similar to ground nutmeg – warm, sweet-spicy, and a bit woody. In wines, nutmeg notes might come from oak aging or complexity in certain rich wines, giving a gentle baking spice character. It’s not as sharp as clove or cinnamon; rather, it’s softer and rounder. The presence of a nutmeg note adds a cozy spiciness (think holiday eggnog or custard sprinkled with nutmeg) which can complement fruit flavors nicely.",
  "nutty": "A general term for aromas or flavors reminiscent of nuts. A nutty wine might evoke almonds, hazelnuts, walnuts, or brazil nuts depending on context. This usually comes from oxidative aging (like in Sherry or some aged whites) or lees contact. It can manifest as a roasted almond note, a walnut skin bitterness, or a sweet hazelnut nuance. Nutty elements add complexity – they lend a wine a savory, toasty aspect as if a handful of nuts were mixed in, often accompanying flavors of butter, caramel, or oxidation in certain styles.",
  "oaky": "Indicates the presence of oak-derived aromas and flavors – as one would expect from wine aged in oak barrels. An oaky wine often smells of things like vanilla, cedar, toast, or baking spices due to the oak. You might also sense a bit of woodsmoke or sawdust. On the palate, it can add tannin and a creamy texture. Essentially, oaky describes that wood-influenced character: think of the scent of a new oak barrel, the sweetness of vanilla, the spice of toasted wood, and sometimes a charred or coconut note (from American oak). When balanced, oak can give structure and complexity; if overdone, the wine might taste predominantly of wood.",
  "oily": "Describes both a texture and a subtle aroma – like vegetable oil or lanolin. An oily wine has a viscous, almost slippery mouthfeel, often seen in certain white wines (like some Alsace Pinot Gris or aged Semillon). Aromatically, oily can refer to a faint smell of oil or wax (akin to linseed oil or machine oil, but very subtle and usually not unpleasant). It gives the wine a weighty, coating sensation on the palate, and sometimes a slight sheen or gloss to its flavor, indicating high glycerol or specific grape traits.",
  "olive": "A savory aroma reminiscent of briny olives, particularly black olives. It carries an earthy, salty tang along with a dark, almost meaty fruit scent. In wines like Syrah or some Southern Italian reds, you might get a black olive note that adds complexity. It’s not fruity in a sweet sense – it’s more of a leathery, salty, fermented fruit smell. This can lend the wine a distinctly Mediterranean character, bringing a nice savory counterpoint to any ripe fruit flavors.",
  "onion": "A pungent aroma akin to raw onion or onion skin. Like garlic, an obvious onion smell in wine is generally a flaw related to sulfur compounds (mercaptans). It’s unusual but if present, it’s typically negative – the wine might remind one of oniony BO or vegetable sulfur. In rare positive contexts, very slight onion skin could describe a nuance in oxidation (like Sherry), but as a fresh onion note, it’s not considered desirable.",
  "opulent": "Describes a wine that is lavish, richly textured, and generous in flavor. An opulent wine often has a full body, high glycerin, and luxurious, ripe fruit that gives a sense of sweetness (even if the wine is dry). Drinking it feels like indulging – it’s velvety, mouth-filling, and maybe a bit heady. Opulent wines typically have layers of flavor (ripe fruit, spice, oak) that all come across as plush and showy, making the tasting experience feel decadent.",
  "orange": "A citrus aroma or flavor like that of an orange – sweet and bright. In some wines, especially aromatic whites or orange wines (white wines made with skin contact), you can detect an orange note, be it like orange juice, orange zest, or blossoms. This adds a pleasant citrusy sweetness and zing. It’s usually accompanied by floral aspects (orange blossom) or candied peel nuances if in sweeter wines. Overall, an orange note lifts the wine with a sunny, citrus fruit character.",
  "orange blossom": "A floral aroma of orange blossoms, the flowers of the orange tree. This scent is intensely sweet, airy, and citrusy-floral. In wine, orange blossom notes are often found in fragrant whites (like Muscat, Albariño, or Viognier), giving a perfume that’s both floral and suggestive of the citrus fruit. It’s an enchanting note that adds elegance – imagine walking by a blooming orange tree on a warm night; that heady, sweet fragrance is what orange blossom brings to a wine’s bouquet.",
  "overripe": "Describes flavors or aromas that suggest the grapes were extremely ripe (even too ripe) when picked. An overripe wine tends to have very lush, sometimes cooked fruit character with lower acidity. You might taste stewed fruits, jam, or even raisin-like notes rather than fresh fruit. Aromas could lean toward prune, fig, or syrupy sweetness. While ripeness gives intensity, overripe implies it’s a bit too far – the wine can feel heavy, lacking freshness, and may have a higher alcohol or a slight porty quality from those super-mature grapes.",
  "oxidized": "Describes a wine that has been exposed to oxygen more than intended, resulting in specific aroma/flavor changes. An oxidized wine often smells nutty, sherry-like or like bruised apples, and the fruit flavors will be dulled or turned to more dried fruit notes. White wines darken towards gold/brown and gain caramel, nut, or apple cider characteristics; red wines can turn tawny and taste flat, with dried fruit and nuts. In general, oxidized indicates the wine has lost its fresh aromas and has taken on an “old,” somewhat stale character (similar to how a sliced apple turns brown and smells different). In most cases (except deliberately oxidized styles like Sherry), this is considered a fault.",
  "papaya": "A tropical fruit aroma reminiscent of ripe papaya. It’s sweet and mellow, with a scent that’s a mix of melon and mango but creamier and less tangy. In wine, papaya notes might appear in very ripe, tropical white wines or some New World Chardonnays/Chenins, giving a soft tropical-fruit character. It adds to the exotic profile of the wine, making it smell like a blend of tropical fruit salad – the papaya element is that gentle, sweet, almost musky tropical note.",
  "passion fruit": "A vibrant tropical aroma strongly associated with some Sauvignon Blancs (especially from New Zealand). Passion fruit smells tangy, exotic, and very fruity – like a mix of citrus, guava, and mango with a sharp tropical punch. In wine, this note makes the aroma jump out as very fruity and fresh, sometimes slightly tart as well. It contributes a bold tropical character that can be quite distinctive, adding to the wine’s allure with something that smells like tropical juice.",
  "peach": "A stone fruit aroma like that of a ripe peach. It’s sweet, juicy, and a little floral. In many white wines (e.g., Riesling, Moscato, some Chardonnays), peach notes are common and very appealing – it’s like the smell you get when biting into a ripe yellow peach, dripping with juice. This note gives the wine a friendly, luscious fruit character. Depending on ripeness, it could range from the fresher scent of a just-ripe peach to the almost syrupy note of canned peaches in heavy syrup.",
  "pear": "The scent of dried pear or pear chips – a concentrated pear aroma that’s sweeter and a bit caramelized compared to fresh pear. Dried pear notes in wine often appear in richer whites or dessert wines, giving a candied or compote-like fruit character. It’s as if the pear’s essence is intensified, with some honeyed and lightly brown sugar tones. This adds depth to the wine’s fruitiness, leaning more towards a dessert-like, developed fruit profile rather than fresh.",
  "peardrop": "The aroma of pear drop candies, a type of hard candy that smells like artificial pear and banana. It’s a distinctly sweet, estery scent – very confectionary and reminiscent of some young Beaujolais or certain fermentation aromas. When a wine is described as having a peardrop note, it means you get that candy-like pear fragrance (mixed with a bit of nail-polish/banana ester). It often indicates a young, carbonically fermented red or a specific ester presence, lending a playful, candied fruit element to the nose.",
  "pencil shavings": "An aroma that combines cedar wood and graphite, much like the smell when you sharpen a pencil. It’s a mix of woody and mineral scents. In red wines (notably Bordeaux blends or Cabernet Franc), “pencil shavings” is a classic descriptor – it suggests a refined cedar note from oak and a graphite/mineral note likely from the wine’s structure. This aroma adds an elegant touch, evoking imagery of cedar cigar boxes and freshly sharpened pencils; it often signifies a certain pedigree in the wine and complements its fruit with a subtle woody-mineral complexity.",
  "peony": "A floral aroma akin to peony flowers – which are rosy, soft, and slightly green in scent. Peony in wine is a delicate red floral note (less potent than rose, more so than violets). Some red wines, like certain Pinots or Beaujolais, can exhibit peony-like aromas, contributing a gentle, charming floral lift to the bouquet. It’s the kind of subtle flower scent that sits in the background, giving the wine a touch of elegance and prettiness without dominating its other aromas.",
  "perfumed": "Describes a wine with highly aromatic, flower-like and sweet scents, as if one were smelling a fine perfume. A perfumed wine is very fragrant – often with abundant floral, spice, or exotic fruit notes that captivate the nose. For example, many aromatic whites (like Gewürztraminer or Moscato) are perfumed: they fill the glass with lush scents of rose, jasmine, lychee, etc. This term emphasizes the wine’s intense and pleasant aromatic qualities, suggesting complexity and allure in the bouquet, much like a well-crafted perfume.",
  "persimmon": "A fruit note reminiscent of ripe persimmon, which has a sweet, mellow pumpkin-like flavor when fully ripe. The aroma is subtle, honeyed-orange and autumnal. In wine, persimmon might not be a common descriptor, but if used it indicates a gentle sweet-orange fruit tone with a bit of earthiness. It could appear in some rich whites or orange wines, adding a unique late-fall fruit character (imagine something between dried apricot and pumpkin flesh). It lends an interesting, soft fruit sweetness that’s a bit different from typical citrus or stone fruit notes.",
  "petrichor": "The distinctive smell of rain on dry earth or pavement. It’s that fresh, mineral, slightly dusty scent that rises from the ground when rain first falls after a long dry spell. In wine, petrichor is used to describe a very fine-grained earthy minerality – as if the wine carries an essence of wet stones and soil after rain. This note can be found in some highly mineral wines (like certain Rieslings or Syrahs) and adds a nostalgic earth-scented freshness to the aroma, evoking imagery of thunderstorms and wet pebbles.",
  "petrol": "A unique aroma often found in aged Riesling, reminiscent of gasoline or kerosene. While it might sound odd, in appropriate measure it’s considered a positive varietal trait for mature Rieslings. The petrol note smells like the fumes of a gas heater or a fuel can – a mix of chemical, rubbery, and oily scents. It adds complexity to the wine’s bouquet, intertwining with the citrus and mineral notes typical of Riesling. In other wines, a strong petrol/kerosene smell could indicate a flaw or sunstruck wine, but in Riesling, aficionados often appreciate a hint of this distinctive aroma as part of the wine’s character.",
  "pine": "An aroma of pine wood or pine resin, evocative of a pine forest or sap. It’s woody, fresh, and slightly balsamic (think Christmas tree scent or resinous Greek retsina wine). In some wines, especially those aged in certain pine barrels or very herbal reds, you might get a pine-like note. It brings a cooling evergreen character, as if a dash of pine sap or needles were present. This can add an interesting resinous, herbal depth to the wine, although if too strong it can dominate the profile (as intentionally in retsina, which is explicitly resinated).",
  "pineapple": "A tropical fruit aroma like that of ripe pineapple. It’s sweet, bright, and a bit tangy. In wine, pineapple notes often appear in warm-climate white wines or those that underwent certain fermentations (like some Chardonnays or Pinot Grigios), lending a juicy, tropical flair. This note makes the wine’s fruit profile feel exuberant and sun-kissed – akin to the smell of freshly cut pineapple chunks, complete with that balance of sugar and acidity. It adds an appealing lusciousness and is usually a sign of ripe grapes and a crowd-pleasing flavor.",
  "plum": "A fruit note reminiscent of plums, usually meaning dark plums unless specified otherwise. It smells of sweet, ripe stone fruit with a bit of skin tartness. In many red wines (Merlot, Malbec, etc.), plum is a common descriptor, providing a sense of round, purple fruitiness. It can range from the lighter, fresher aroma of red plums to the deeper, jammy notes of black plums. Plum character in wine adds a friendly, rich fruit base – it’s less sharp than berry and less floral than cherry, giving a solid core of fruit that’s juicy and smooth.",
  "polished": "Describes a wine that is smooth, refined, and well-crafted in texture and flavor. A polished wine has no rough edges – tannins are silky, acids are integrated, and flavors are harmonious. Tasting it is like feeling polished marble: seamless and sleek. This term often applies to higher-end wines where everything feels carefully resolved and elegant. The wine glides over the palate with grace, indicating quality and skilled winemaking, leaving an impression of finesse and completeness.",
  "pomegranate": "A red fruit note akin to pomegranate seeds or juice. Pomegranate in wine brings a tart, tangy berry-cherry quality with a slight astringency (like the bitterness of the seeds). It’s both fruity and a touch floral. In tasting, citing pomegranate means the wine has bright red fruit characteristics that are a bit more tart or exotic than standard cherry or berry. It can be found in certain vibrant reds or rosés, adding a crisp, cranberry-like snap of flavor that keeps the wine feeling lively.",
  "potpourri": "An aroma that smells like a mix of dried flowers, spices, and herbs – essentially the scent of potpourri. It’s complex: you might detect dried rose petals, lavender, maybe a touch of clove or citrus peel all together. In wine, a potpourri note indicates a heady, perfumed mix of dried floral and spice elements. This is often associated with nuanced, mature wines or certain Rhône reds (like aged Châteauneuf-du-Pape) that exhibit an array of sweet dried flower and herbal scents. It gives the wine a rich aromatic tapestry, reminiscent of sniffing a bowl of decorative dried flowers and spices.",
  "powerful": "Describes a wine with very intense presence – whether through high alcohol, concentrated flavor, or both. A powerful wine immediately commands attention on the palate; it’s full-bodied, with robust flavors that might include dense fruit, oak, and ample tannin or warmth. This kind of wine can feel “big” and forceful, saturating your taste buds. It’s not subtle or delicate – instead it’s assertive, and you sense its strength in each sip. Such wines often benefit from hearty food pairings or aging to mellow their might.",
  "prune": "An aroma of dried plums (prunes), which is deep, sweet, and slightly raisined. Prune notes often develop in wines made from very ripe grapes or wines that have aged a long time, especially fortified or warm-climate reds. It indicates the fresh plum has moved to a denser, sweeter profile with hints of fig and raisin. This adds a rich, mature fruit character to the wine, leaning towards the dessert fruit spectrum. While a bit of prune can give complexity, too much might suggest overripe or oxidized fruit, making the wine taste flat if freshness is lost.",
  "pungent": "A general term meaning the wine has a very strong, intense smell that sharply catches your attention (not necessarily in a good way). A pungent aroma in wine could be something like a strong sulfur smell, an acrid vinegar note, or even an overwhelmingly green or spicy odor – anything that is penetrating and forceful to the nose. It often implies something is off or extreme: for example, a wine high in volatile acidity might have a pungent vinegar/solvent smell. Essentially, if a wine’s aroma is described as pungent, it’s powerful and often not very pleasant or refined, coming on too strong in one particular aspect (spice, acid, sulfur, etc.).",
  "quince": "A fruit aroma similar to quince paste or cooked quince, which is like a combination of apple and pear but more aromatic and often detected in a jelly/jam form. Quince is tart and floral when fresh, but usually enjoyed cooked, which yields a honeyed, apple-pear marmalade scent. In wine, quince notes can appear in certain structured whites or aged sweet wines, adding an old-fashioned orchard fruit complexity. It gives the impression of a spiced pear/apple preserve – fragrant, slightly tangy-sweet, and exotic. Mentioning quince often highlights an elegant fruit nuance beyond common apples and pears.",
  "racy": "Describes a wine with high, zingy acidity that gives it an exciting, brisk character. A racy wine tingles the palate; it’s vibrant and energetic due to that acidity, often coupled with pronounced minerality. Tasting a racy wine is like experiencing a bolt of lightning – it has focus and intensity, especially on the back of the tongue and cheeks (mouth-watering effect). This term is usually a compliment, suggesting the wine is lean, sharply defined, and lively (commonly used for Rieslings, Loire whites, etc.), providing a very clean and refreshing profile.",
  "raisin": "The aroma or flavor of raisins (dried grapes) – sweet, concentrated, and a bit caramelized. In wine, raisin notes typically indicate very ripe grapes or partial drying (as in Amarone or dessert wines). It smells like a mix of grape candy and dried fruit sweetness. While small hints can add richness, a pronounced raisin character can mean the wine edges toward a fortified or oxidized style. On the palate it imparts sugary dried fruit tones and often a higher alcohol warmth. So, raisin contributes a deep, sweet, brown-ish fruitiness reminiscent of raisins or even dates, enhancing the wine’s complexity in certain styles.",
  "raspberry": "A red fruit aroma akin to ripe raspberries. It’s bright, sweet-tart, and very fragrant – imagine the smell when you crush a handful of fresh raspberries. In many red wines (Pinot Noir, Grenache, etc.), raspberry notes are common, giving a youthful, juicy red berry character. It can range from the candy-like scent of raspberry jam (if very ripe) to the zesty freshness of just-picked berries. This note makes a wine’s fruit profile feel lively and charming, often balancing more serious flavors with its lighthearted, sweet red-fruit tone.",
  "red currant": "An aroma of red currants – small, tart red berries. Red currant smells like a mix of cranberry and raspberry but more on the tart, earthy side. In wine, red currant notes often suggest a bright, slightly sour red fruit element, common in some cool-climate reds or Bordeaux blends. It gives a wine crisp fruitiness without too much sweetness, kind of a crunchy berry vibe. This contributes to complexity by adding a tangy fruit note that can counterbalance richer flavors.",
  "red plum": "The aroma of red-fleshed plums, which are slightly lighter and more tart than dark plums. Think of the scent when biting into a red or yellow plum – sweet but with a fresh zing near the skin. In wine, red plum notes indicate a gentle, rounded fruit presence that isn’t overly deep or dried. It’s often found in Merlot or other medium-bodied reds, lending a smooth, easy fruit character. Compared to black plum (which is denser), red plum is a touch brighter and more delicate, adding to a wine’s approachability and soft fruit impression.",
  "rhubarb": "A tart, vegetal-fruit aroma reminiscent of fresh rhubarb stalks or rhubarb pie. Rhubarb smells a bit like sour red berries crossed with green herbal tones – it’s distinctly sharp yet pleasing in a culinary way. In wine, a rhubarb note might appear in certain high-acid reds or rosés, giving a tangy red fruit and earthy green combo. It can make the wine interesting by adding that slightly sour, garden-vegetal hint (like the smell of cutting rhubarb). Often, rhubarb in wine points to a puckering, cool climate style with restrained sweetness and an edgy fruit profile.",
  "rich": "Describes a wine with abundant flavor and texture, often leaning towards sweetness or ripeness. A rich wine fills your mouth with layers of flavor – whether it’s dense fruit, creamy oak, or high alcohol giving weight. It conveys a sense of fullness and generosity; the opposite of thin or austere. For instance, a rich Chardonnay might have bold tropical fruit, butter, and vanilla in spades. The term implies the wine is luxurious in mouthfeel and taste, delivering a lot of substance. Rich wines can be very satisfying, though they need balance to not feel cloying or heavy.",
  "robust": "A term for a wine that is full-bodied, strong, and bursting with flavor – similar to calling it hearty or vigorous. A robust wine often has high alcohol or tannin, bold fruit, and possibly noticeable spice or oak. It stands up well to flavorful foods because it has its own intensity. Drinking a robust wine is a big experience: it’s not subtle or delicate, but rather assertive and muscle-bound (think robust like a strong handshake). This quality is often found in rustic or high-alcohol reds (like a rustic Italian red or a powerful Zin), which deliver a hearty punch on the palate.",
  "rose": "A floral aroma of rose petals, often associated with aromatic grape varieties. It’s the classic sweet, soft smell of a blooming rose – perfumed and romantic. In wines like Gewürztraminer, Muscat, or even some Pinots, a rose note can be quite prominent, adding an elegant bouquet element. It makes the wine smell like a bouquet of roses was dipped into it. This aromatic note tends to indicate a very fragrant wine, contributing a sense of sweetness and luxury on the nose (even if the wine is dry).",
  "rosemary": "An herbal aroma like that of fresh or dried rosemary. Rosemary has a strong, resinous pine-and-mint scent with a bit of woodiness. In wine, rosemary notes might appear in Mediterranean reds or those with a herbal garrigue profile, giving a savory, kitchen-herb character. It adds depth by bringing in that aromatic herb garden element – you smell hints of roast lamb herbs or focaccia seasoning. Rosemary in moderation can make a wine intriguing, lending a warming, earthy-herbal complexity to the flavor profile.",
  "rotten egg": "An off-putting odor identical to the smell of a rotten egg, caused by hydrogen sulfide (H₂S) in the wine. This is a strong sulfuric stench – foul and unmistakable. If a wine smells of rotten eggs, it’s a flaw; likely the result of reductive winemaking issues. The aroma is extremely pungent (like sulfur or sewage) and overwhelms pleasant scents, rendering the wine essentially undrinkable until the issue is resolved (sometimes decanting can dissipate mild cases). In short, any hint of rotten egg means something went wrong in the bottle or barrel, as no healthy wine should carry that aroma.",
  "round": "Describes a wine with a smooth, gentle mouthfeel and no harsh edges; it feels complete and satisfying on the palate. A round wine typically has moderate acidity and tannin that are well-integrated, giving a sense of softness. Flavors transition seamlessly. For example, a red wine with lush fruit and supple tannins can be called round if nothing juts out aggressively. It’s the kind of wine that glides rather than grips – very approachable and polished, often associated with a well-balanced, medium- to full-bodied style that caresses the mouth.",
  "saffron": "A rare spice note reminiscent of saffron threads. Saffron has a distinctive warm, hay-like, slightly medicinal floral scent (famous in paella or risotto). In wine, saffron notes might appear in some aged sweet wines or whites, adding an exotic spice and earthy floral nuance. It’s subtle but complex – if you detect saffron, the wine likely has a layered bouquet. This aroma contributes a luxurious, spicy-floral touch that is quite unique, hinting at complexity akin to fine tea or spice markets.",
  "sage": "An herbal aroma akin to sage leaves – earthy, camphorous, and savory-green. It’s the smell you get when you rub fresh sage: pungent and slightly peppery with a soft resinous quality. In wine, sage notes often surface in earthy reds or those from scrubland terroirs, infusing a wild-herb character. It gives the wine a savory dimension, as if a hint of dried sage or herbes de Provence is mixed in. This can complement the fruit with an intriguing herbal layer, enhancing complexity especially in Mediterranean-style wines.",
  "saline": "A subtle aroma or taste of saltiness, like a sea breeze or saline solution. In certain wines (especially those from coastal vineyards or specific soils), you might perceive a briny note that isn’t literally salty to taste but gives an impression of salt air or ocean spray. We call that saline. On the palate it can also create a slight salivating effect. This characteristic adds crispness and can make a wine feel refreshing – imagine the faint saltiness you sense when near the sea. It often accompanies mineral profiles, enhancing the wine’s complexity with a delicate savory note.",
  "savory": "Describes flavors or aromas that are not sweet but more aligned with herbs, umami, and spice – like broth, soy, grilled meat, or herbs. A savory wine emphasizes earth, spice, and non-fruit elements (think black olive, tobacco, leather, dried herbs) rather than overt fruity sweetness. Tasting a savory wine can remind you of food-like qualities (soy sauce, roasted game, tomato, etc.). This trait often appears in certain Old World reds or aged wines, making them pair exceptionally well with food since they bring their own seasoning-like complexity.",
  "sharp": "An adjective for a wine that has a pronounced, pointed bite – usually from high acidity or occasionally very high alcohol (in a hot sense). A sharp wine comes across as piercing or edgy on the palate. For instance, a wine with sharp acidity will immediately cause a tangy, almost sour jolt to your tongue (imagine under-ripe citrus). If describing aroma, sharp could also mean a pungent note like vinegar or solvent is evident. Overall, calling a wine sharp implies it’s a bit aggressive in one aspect, lacking smoothness and potentially in need of more balance or age to mellow out.",
  "silky": "Describes an exceptionally smooth, fine texture in a wine, especially with reference to tannins. A silky wine glides over the palate like silk – it’s soft, delicate, and polished. The mouthfeel is luxurious, with tannins that are present but feel very fine-grained and gentle. Often used for well-aged reds or impeccably balanced wines, silky indicates a high quality of texture. Flavor-wise, everything in a silky wine seems harmonious and refined, with nothing coarse or out of place as you taste it.",
  "slate": "A mineral aroma or taste associated with slate rocks (often noted in wines from slate-rich soils, like Mosel Riesling). It smells like wet stones or pencil lead, giving a steely, earthy impression. Slate isn’t a smell of fruit or flowers; it’s almost like sniffing a piece of cold stone – subtle but distinct once you recognize it. In wine, a slate note contributes to the perception of minerality – a dry, flinty character that can balance out fruitiness. It’s usually a sign of a precise, terroir-driven wine, adding depth and a sense of place (like the craggy slate slopes where some vines grow).",
  "smoky": "An aroma that suggests smoke or burnt wood. This can come from oak barrel toasting or sometimes from specific terroirs or even smoke exposure. A smoky note in wine might smell like a faint campfire, charred embers, or toasted bread. It adds a warm, rustic character. For example, some Syrahs have a lovely smoky/bacon aroma, or an oaked Chardonnay might carry a whiff of smoke from the barrel char. This note, when balanced, can lend complexity and an almost grilling-like savory element. However, if excessive (like in a wine affected by wildfire smoke), it can dominate unpleasantly, tasting ashy.",
  "smooth": "Refers to a wine with a pleasing, easy texture and well-integrated flavors/tannins. A smooth wine goes down effortlessly; nothing harsh or bitter catches your palate. The tannins (if a red) are soft and velvety, the acids are gentle, and the wine feels round. Often used for reds that are mellow or whites that are creamy, smooth is generally positive, implying the wine is polished and approachable. It may not always mean the wine is very complex, but it does mean you won’t be jangled by rough edges – it’s a comfortable, satisfying drink.",
  "soapy": "An unusual aroma that can resemble scented soap or perfumed soap suds. It’s somewhat floral and waxy but with a cleansing-product quality. A soapy note in wine often comes from high levels of certain aldehydes or improper clarification, and it’s typically considered a fault or at least odd. The smell might remind one of lavender soap or laundry soap, giving the wine a perfumey, slick aroma that doesn’t belong. It can also slightly affect taste, making it feel slick or chemically floral. A faint hint might be overshadowed by other notes, but if you distinctly think “soap,” the wine likely has an imbalance or minor flaw in its aroma profile.",
  "soft": "Indicates a wine with low acidity and/or gentle tannins, yielding a mellow, plush mouthfeel. A soft wine won’t poke or prod your palate – it’s kind and yielding in structure. The term is often applied to easy-drinking wines or those with a bit of sweetness that round out any edges. For example, a soft red may have mild tannin and lower acid so it feels smooth and cushioned. Soft doesn’t mean flavorless; the wine can be fruity and full, but everything about it is undemanding on your mouth. It’s the opposite of sharp or harsh – instead, think smooth, round, and cuddly in wine form.",
  "sour cherry": "The aroma or taste of tart red cherries (like Morello cherries used in baking). Sour cherry is bright and tangy, less sweet than regular cherry, with a slight pucker. In wine, especially some Italian reds (like Sangiovese-based wines), sour cherry notes are classic – they give a high-toned red fruit brightness and a bit of pleasant bitterness. This flavor lifts the wine, making it mouth-watering and adding complexity alongside sweeter fruit notes. It’s as if a touch of cherry skin sourness or a dash of cherry pit bitterness accompanies the fruit, which can be very appetizing and food-friendly.",
  "spicy": "Having noticeable spice-like aromas or flavors, akin to spices used in cooking or baking. This is a broad descriptor – a spicy wine might exhibit black pepper, cloves, cinnamon, anise, ginger, or chili-like heat in its profile. It doesn’t mean the wine literally contains spices, but compounds from oak or grape skins can mimic those sensations. For example, a Zinfandel could be called spicy if it has peppery and cinnamon notes. Spicy gives the wine a lively kick beyond fruit: it tingles the senses a bit, much as actual spices do in food, and adds excitement and complexity to the aroma/flavor.",
  "stalky": "An aroma or taste that suggests grape stems or green twigs. It’s a green, slightly woody note often from wines that had significant stem contact (like whole-cluster fermentations). Stalky can manifest as a kind of bitter green wood or vegetal flavor – imagine chewing on a grape stem or a bit of bark. In moderation, it can contribute structure or an intriguing herbal character, but if too pronounced it can make the wine seem under-ripe or astringent. It’s generally a term you’d use when a wine’s tannin or flavor has that raw plant quality, hinting at stems or seeds.",
  "stewed fruit": "A flavor and aroma profile that suggests fruits have been cooked down, like in a compote or stew. Instead of bright, fresh fruit, you get soft, mixed fruit notes often with a slightly caramelized or jammy edge – like the filling of a pie or a pot of mixed berries simmered with sugar. In a wine, stewed fruit indicates very ripe fruit that’s lost some definition (common in hot-climate or overripe wines). You might detect something akin to stewed plums, cooked strawberries, or syrupy berry mix. This gives the wine a rich, homogenous fruit sweetness but can also mean it’s low in freshness – the opposite of vibrant or crisp fruit. In balanced measure it can be homely and pleasant, but too much stewed character might suggest the wine is flabby or made from overripe grapes.",
  "strawberry": "A red fruit aroma like that of ripe strawberries. It’s sweet, aromatic, and friendly – think of the smell when you bite into a fresh strawberry on a summer day, or even strawberry jam for a sweeter version. This note is common in many rosés and lighter reds (like Pinot Noir or Beaujolais), lending a charming, easy fruitiness. It can range from fresh wild strawberry (more delicate and perfumed) to candied strawberry (like in some youthful wines). The presence of strawberry makes a wine feel approachable and youthful, and often it’s one of multiple red fruit notes that together shape the wine’s fruity profile.",
  "sun-dried tomato": "A savory aroma reminiscent of tomatoes that have been dried under the sun (concentrating their flavor). It smells like intense, slightly sweet tomato with an herbal, almost leathery edge. In certain wines (occasionally in some Italian reds or warm-climate Syrahs), a sun-dried tomato note can appear, giving a tangy, umami-rich nuance. This is different from fresh tomato leaf or green tomato – it’s more about the dried, slightly smoky tomato skin. It adds a rustic, Mediterranean touch to a wine’s aroma, bridging the gap between fruity and savory.",
  "supple": "Describes a wine with a smooth, pliant texture and gentle, well-resolved tannins. A supple wine feels caressing on the palate – there is structure, but it’s flexible and yielding rather than firm. It’s often used for red wines whose tannins have softened (either through aging or good ripeness) so that they provide body without roughness. Flavors in a supple wine flow easily; nothing is awkward or stiff. In essence, to call a wine supple is to praise how it moves in your mouth – gracefully and without resistance, offering richness and softness at the same time.",
  "sweet": "Having a noticeable level of sugar-derived sweetness on the palate. A sweet wine tastes sugary, like desserts or ripe fruit syrup – common in wines like Sauternes, Port, or late-harvest Riesling. The term can also describe aromas that give an illusion of sweetness (such as very ripe fruit, vanilla, or honey notes), even if the wine is technically dry. When you say a wine is sweet without qualification, you usually mean it contains residual sugar that you can clearly taste (as opposed to a dry wine). The sweetness often brings flavors of honey, candied fruit, or sugar-coated nuts, and contributes a viscous, full body. Balance is key: a sweet wine should also have acidity to avoid being cloying.",
  "tannic": "Describes a wine high in tannins – those compounds mostly from grape skins, seeds, and oak that create a drying, astringent sensation. A tannic wine will make your mouth feel somewhat dry or rough, similar to strong black tea. The term often applies to young red wines (like Cabernet Sauvignon or Nebbiolo) that have a big structure. Tannins themselves don’t have a strong flavor; it’s more of a textural and slightly bitter sensation. Saying a wine is tannic means this drying effect is a dominant characteristic at its current state. Over time or with food, tannins can soften. While tannins provide backbone and aging potential, a very tannic wine when young can feel harsh – the key is that the fruit and other elements catch up to integrate with the tannin.",
  "tar": "An aroma reminiscent of tar or asphalt, often noted in certain robust red wines (famously in Barolo, which is described as “tar and roses”). It’s a dense, smoky, resinous smell – think of freshly paved road or roofing tar. In wine, a tar note provides a deep, dark counterpoint to fruit and floral elements. It might seem odd, but in small amounts it adds intrigue and complexity. The presence of tar typically signals a wine with serious structure and intensity. On the palate, one doesn’t exactly “taste tar,” but you can get a sense of that chewy, smoky character intertwined with bold fruit and earth. It’s generally a positive descriptor in the right context, indicating a powerful, evocative aroma.",
  "tart": "A taste sensation of high acidity that is sour or puckering, similar to unripe fruit or lemon juice. If a wine is described as tart, it means it leans towards sharp acidity in its flavor profile – imagine biting a cranberry or a green apple. Tartness can be refreshing and make a wine food-friendly, but if overwhelming it might feel unbalanced. Some wines are intentionally crafted to be a bit tart (like certain light whites or rosés) to emphasize brightness. Essentially, calling a wine tart highlights its sour-acidic snap that can enliven the palate, though one would hope it’s matched by enough fruit or sweetness so it doesn’t become too austere.",
  "thin": "Describes a wine that feels light-bodied and lacking in flavor intensity or concentration. A thin wine might taste diluted, watery or simply under-fruited – as if it’s missing the mid-palate weight. It often comes paired with high acid, making it feel more like flavored water than rich wine. The term is usually negative, suggesting the wine doesn’t carry enough substance (ripe fruit, glycerin, etc.) to be satisfying. For instance, an over-cropped or underripe wine might come off as thin if the grapes didn’t have much to give. Such a wine may have some aroma and flavor, but they are fleeting, and the overall impression is of weakness or hollowness on the palate.",
  "thyme": "An herbal aroma like fresh or dried thyme leaves. Thyme has a savory, slightly minty and lemony herb scent that is prominent in Mediterranean cooking. In wine, especially those from regions with wild herbs (think Provence or parts of Spain/Italy), a thyme note can surface, adding a green, earthy spiciness. It contributes to the wine’s complexity by layering in that dried herbal character – as if a sprig of thyme had been steeped in it. Along with rosemary, bay, etc., thyme falls under the garrigue family of notes, painting a picture of shrubby hillsides and adding a pleasant savory quality.",
  "tight": "Describes a wine that is closed in and not expressing much aroma or flavor, often due to youth. A tight wine feels constricted – you sense the structure (acid/tannins) more than the actual flavors. It’s like the wine is holding back. On the palate, a tight wine might show some promise but everything is compact and not giving. This is common in young high-end wines that need time or air. Calling a wine tight typically suggests that if you decant or age it, it should “loosen up” and reveal more. In the moment, though, it means you have to search for the aromas/flavors because they aren’t readily apparent or they feel bound up by the wine’s structure.",
  "toast": "An aroma of toasted bread or lightly charred toast, usually a sign of oak barrel influence (from the toasting of barrel staves) or yeast aging. It smells like the crust of freshly toasted baguette – warm, grainy, and slightly smoky. In sparkling wines, a toasty note is highly prized, coming from time on lees and resembling brioche or toast. In still wines, the term might indicate a light char from the oak (complementing vanilla and spice tones). This note adds a comforting, breakfasty warmth to the wine’s nose, rounding out fruit with a subtle roasty nuance that can be quite inviting.",
  "tobacco": "An aroma reminiscent of cured tobacco leaves or a freshly opened cigar box. It’s a warm, woody, slightly sweet dried-leaf smell with a hint of smokiness. Many complex red wines (like Cabernet, Bordeaux blends, or Tempranillo) develop a tobacco note, especially with some age. It adds a sophisticated, earthy layer to the bouquet, as if you stepped into a humidor. The scent can range from fresh pipe tobacco (more sweet and aromatic) to drier cigar-box cedar. In any case, it’s generally seen as a positive trait in moderation, contributing to the wine’s savory and tertiary aromatic profile.",
  "toffee": "A sweet, caramelized aroma reminiscent of buttery toffee candy or caramel fudge. It combines the smell of burnt sugar and butter – rich and decadent. In wine, toffee notes can appear in well-oaked whites, some dessert wines, or aged wines that develop those caramel tones. It indicates a certain sweetness (even if the wine is dry) and oak influence, as vanilla and caramel from oak can merge into a toffee impression. This adds a dessert-like charm to the aroma, often accompanying notes of vanilla, butterscotch, or coffee. Essentially, it’s that creamy burnt sugar scent that can make a wine smell luxurious and indulgent.",
  "tomato": "An aroma or flavor note reminiscent of tomatoes – usually more like the green stem or a just-cut tomato than the cooked kind. In some wines, especially certain Italian reds or occasionally Sauvignon Blancs, you might get a faint note of tomato skin or fresh tomato flesh, which is a slightly sweet-green smell. It can lend an interesting rustic or vegetal nuance. However, if someone says a wine tastes like tomato juice or sauce (more common in flawed or very oxidized wines), that’s usually not a good thing. Generally, a subtle tomato leaf or tomato flesh note adds to a wine’s herbaceous complexity, tying in with other green or earthy elements.",
  "tomato leaf": "A specific green, aromatic note identical to the smell you get when rubbing tomato plant leaves. It’s very pungent-green, with a sharp yet fresh garden scent. In wine, tomato leaf is most famously a descriptor for some styles of Sauvignon Blanc or Cabernet Franc, indicating pronounced pyrazines (the compounds responsible for herbaceous aromas). It gives a wine a distinctive vegetative character – like sniffing a tomato vine on a warm day. This can be appealing if balanced, contributing to a fresh, herbaceous profile that adds dimension, but if too dominant it may make the wine smell overly green or unripe.",
  "truffle": "An earthy, pungent aroma reminiscent of truffle fungus (the gourmet underground mushrooms). Truffles have a very distinctive scent – musky, garlicky, and soil-like all at once, considered highly complex and alluring. In certain fine aged wines (especially Burgundies, Barolos, etc.), a truffle note can emerge, giving the wine a luxurious earthy savoriness. It’s often described as earthy mushroom with a touch of garlic and forest floor. This aroma adds immense complexity and is usually seen as a sign of a wine’s maturation and high pedigree. It contributes a deep umami character that plays beautifully with savory foods.",
  "underripe": "Describes flavors or aromas that indicate the grapes were not fully ripe when picked. An underripe wine often has green, vegetal, or excessively tart elements – for example, green bell pepper, grass, or very sour fruit notes that lack sweetness. The tannins might also be harsh because they didn’t soften on the vine. If someone calls a wine underripe, they mean it tastes a bit raw or thin, with fruit that’s more acid-driven and possibly herbal to the point of imbalance. Think of biting into an under-ripe plum – it’s hard, green-tasting, and not very aromatic. In wine, that translates to a lack of depth and a prominence of green flavors.",
  "vanilla": "A sweet baking aroma derived largely from oak aging. Vanilla in wine smells like vanilla extract or vanilla bean – warm, creamy, and dessert-like. New oak barrels (especially those made from American oak) impart vanillin compounds, giving wines a distinctive vanilla note often noticeable in Chardonnays, Rioja, or Cabernet aged in oak. This note can add a sense of sweetness even if the wine is dry, complementing fruit flavors with a custardy touch. It’s generally a welcome aroma when balanced, contributing to the complexity and “polish” of a wine’s bouquet, much like vanilla is used to enhance desserts.",
  "vegetal": "A term for aromas/flavors that are vegetable-like or green plant-like. A vegetal wine might remind one of green beans, bell peppers, cabbage or stems – essentially notes that are more garden than orchard. This often comes from unripe grapes or certain grape varieties with high methoxypyrazines. In moderation, light vegetal hints (like cut grass, bell pepper) can add complexity, but vegetal usually suggests it’s a bit too pronounced, making the wine smell or taste more like veggies than fruit. For example, a red wine with strong vegetal character might not have enough ripe fruit to balance its green pepper or bean pod flavors, coming off as under-ripe or rustic.",
  "velvety": "Describes a texture that is smooth and plush, much like the feel of velvet fabric. A velvety wine has soft, fine tannins that coat the mouth gently, and a rich body that gives a sense of fullness without harshness. When you sip it, the wine flows easily and feels luxurious on the tongue – structured yet utterly smooth. This term is often applied to well-aged reds or exceptionally balanced young ones where tannins are present but very refined. It implies both high quality and immediate pleasure; a velvety wine is polished, caressing, and leaves a lingering, gentle finish. It’s a step beyond “smooth,” suggesting an almost tangible plushness in the wine’s mouthfeel.",
  "vinegar": "An aroma of acetic acid, identical to vinegar, which is sharp, sour, and piquant. If a wine smells like vinegar, it means there’s excessive volatile acidity (VA), usually from bacterial spoilage turning some of the wine to acetic acid. The odor is biting – like sniffing white wine vinegar or apple cider vinegar – and it’s a clear fault when strong (though many wines have a tiny amount of VA that can lift aromas without outright vinegar smell). Tasting it might also give a puckering sourness. Essentially, noticeable vinegar in wine signals that the wine has been exposed to oxygen and bacteria enough to partially spoil, and while it might work for salad dressing, it’s not pleasant in your glass.",
  "violet": "A floral aroma evocative of violet flowers. It’s a sweet but subtle dark-floral scent, often found in certain red wines like Malbec, Nebbiolo, or Syrah. Smelling violets in wine means you detect a perfume akin to a bouquet of spring violets – slightly powdery, candy-like (think of parma violet candies), and very elegant. This note adds a beautiful floral lift to the wine’s aroma profile, often pairing with red and black fruit notes to increase the wine’s allure. It signals a refined bouquet, and is typically a positive descriptor indicating aromatic complexity.",
  "volcanic": "A term used to describe a certain mineral quality that hints at volcanic soil origin – think sulfurous, smoky, or basalt-like notes. A wine described as volcanic might have a subtle aroma of pumice, lava rock, or gunpowder (a kind of flinty reduction combined with earthy smoke). It gives an impression of ash or burnt earth in a restrained way. This isn’t a common descriptor outside of context (like wines from Santorini or Mt. Etna, where tasters sometimes note a “volcanic minerality”). It contributes a distinctive sense of place – a rugged, smoky-stony nuance that can make the wine feel linked to volcanic soils. Essentially, calling a note volcanic is highlighting a specific kind of minerality and smokiness.",
  "walnut": "A nutty aroma reminiscent of walnuts, particularly the slightly bitter, oily smell of walnut meat and skins. In wine, walnut notes often appear in oxidized or aged styles (like Sherry, Tawny Port, or mature whites), giving a dry, earthy nut scent. It’s less sweet than almond or hazelnut aromas; walnut has a more savory, woody nut character. This adds complexity, especially to fortified wines – think of the smell of cracked walnuts or walnut shells. Sometimes even in reds you might catch a walnut-skin note as the wine ages. It lends a mature, autumnal quality to the bouquet.",
  "wet dog": "An unpleasant aroma often associated with cork-tainted wine (TCA contamination). It literally smells like a wet dog – musty, damp, and animal. People also compare it to the smell of soggy newspapers or a damp wool sweater. If a wine has wet dog odor, it’s almost certainly flawed, likely corked. The aroma overwhelms fruit and freshness, leaving the wine smelling dank and stale. It’s universally considered a fault; no amount of poetic spin makes “wet dog” a positive in a wine glass.",
  "wet wool": "An aroma that smells like damp wool or a wet sweater – somewhat similar to wet dog but more on the fabric side than the animal side. This note is famously associated with some Chenin Blanc or Semillon wines (and also in minor TCA cases). In certain contexts like a Vouvray Chenin, a faint wet wool can be a varietal quirk and not necessarily a fault, providing an interesting lanolin-like character. It’s a subtle, neutral smell of wet fabric/hair that can accompany fruit aromas. However, if it’s strong, it could be off-putting. In balanced small amounts, some tasters find it adds complexity (descriptors like lanolin are used), but generally it’s not a highly sought aroma unless you’re deep into geeky wine description.",
  "white flowers": "A general term for delicate white-blossomed floral aromas, like those of jasmine, orange blossom, acacia, or hawthorn. If a wine is said to have white flowers on the nose, it means it carries a light, sweet floral perfume reminiscent of spring blossoms. This description avoids pinpointing a specific flower but conveys the impression of something like a mix of citrus blossom, honeysuckle, and similar subtle florals. White flower notes add elegance and finesse to a wine’s aroma, giving a sense of freshness and grace without the headiness of bigger floral notes (like rose). It’s commonly noted in fine whites and sparkling wines.",
  "white pepper": "A spice aroma akin to ground white peppercorn. It’s a more subtle peppery note than black pepper – slightly floral, mildly pungent, and a touch woody. In wine, white pepper is famously associated with Grüner Veltliner and some cool-climate Syrahs. It gives a delicate spiciness that tingles the nose lightly. Unlike the bold kick of black pepper, white pepper in wine feels more like a gentle sprinkle of spice that can enhance the overall aroma complexity. It adds a refined savory element, often meshing well with mineral and herb notes in the wine.",
  "yeasty": "An aroma reminiscent of yeast or rising bread dough. It smells like a bakery in the morning – think of the scent of floury, fermenting dough or the whiff of a beer brewery. In wines, yeasty notes are common in those aged on lees (dead yeast cells), such as Champagne or Muscadet. It can be pleasant, giving bready, brioche-like nuances, and adding depth to the aroma. In young fermenting wine or if a wine hasn’t settled, a yeasty smell might also be present (like the smell of fresh beer or rising dough). Generally, yeasty in a finished wine refers to appealing bread, dough, or pastry crust notes that enrich the nose, signaling techniques like sur lie aging or bottle fermentation.",
  "youthful": "Describes a wine that presents as young and undeveloped in bouquet and flavor. A youthful wine often has vibrant primary notes – lots of fresh fruit, maybe some floral and herb, but not much in the way of earthy or aged characters. Its tannins or acids might be a bit aggressive (since they haven’t mellowed) and the overall impression is lively and straightforward. Saying a wine is youthful implies it could benefit from more time to integrate and gain complexity, but it’s also a nod to the bright, exuberant qualities it has at that moment (fresh grapes, new oak vanilla if present, etc.). In appearance, a youthful red might be more purple-tinted, and a youthful white might be very pale with greenish hues. It’s essentially a wine in its early stage, proudly showing off its simple, fresh charms.",
  "zesty": "An adjective for a wine that is lively and tangy, often with pronounced acidity or citrus-driven flavors. A zesty wine gives a sensation akin to biting into a lemon or sipping something with a spicy kick – it’s refreshing, energetic, and maybe slightly prickly (if lightly effervescent or very acidic). Typically used for whites or rosés, zesty means the wine has a citrus peel or spice brightness that enlivens your palate. Think of Sauvignon Blanc with that grapefruit zing or a young Riesling with limey snap – they feel zesty. The term conveys that the wine is anything but dull; it has pep and brightness, leaving your mouth feeling clean and awakened by the experience.",
};

// Helper function to identify notes in wine descriptions
export function identifyTastingNotes(description: string): string[] {
  if (!description) return [];
  
  const lowercaseDesc = description.toLowerCase();
  const foundNotes: string[] = [];
  
  // Check each note in the guide
  for (const note in WineTastingNotesGuide) {
    // Create variations of the note to check
    const variations = [note];
    
    // Add singular/plural variations
    if (note.endsWith('ies')) {
      variations.push(note.slice(0, -3) + 'y');
    } else if (note.endsWith('s')) {
      variations.push(note.slice(0, -1));
    } else {
      variations.push(note + 's');
    }
    
    // Check if any variation appears in the description
    for (const variation of variations) {
      const regex = new RegExp(`\\b${variation}\\b`, 'i');
      if (regex.test(lowercaseDesc)) {
        foundNotes.push(note);
        break;
      }
    }
  }
  
  return [...new Set(foundNotes)]; // Remove duplicates
}

// Function to find unique notes between wines
export function findUniqueNotes(wine1Notes: string[], wine2Notes: string[], wine3Notes: string[]): {
  wine1Unique: string[],
  wine2Unique: string[],
  wine3Unique: string[]
} {
  const wine1Set = new Set(wine1Notes);
  const wine2Set = new Set(wine2Notes);
  const wine3Set = new Set(wine3Notes);
  
  const wine1Unique = wine1Notes.filter(note => 
    !wine2Set.has(note) && !wine3Set.has(note)
  );
  
  const wine2Unique = wine2Notes.filter(note => 
    !wine1Set.has(note) && !wine3Set.has(note)
  );
  
  const wine3Unique = wine3Notes.filter(note => 
    !wine1Set.has(note) && !wine2Set.has(note)
  );
  
  return {
    wine1Unique,
    wine2Unique,
    wine3Unique
  };
}

// Function to format notes for display
export function formatNoteForDisplay(note: string): string {
  // Special formatting for certain notes
  const specialFormats: { [key: string]: string } = {
    'saline': 'Hint of salinity',
    'salinity': 'Hint of salinity',
    'salt': 'Hint of salinity',
    'brine': 'Briny character',
    'oak': 'Oak influence',
    'vanilla': 'Vanilla notes',
    'citrus': 'Citrus notes',
    'berry': 'Berry character',
    'floral': 'Floral notes',
    'herbal': 'Herbal character',
    'mineral': 'Mineral notes',
    'spicy': 'Spicy character',
    'earthy': 'Earthy notes',
    'fruity': 'Fruit-forward'
  };
  
  if (specialFormats[note]) {
    return specialFormats[note];
  }
  
  // Capitalize first letter
  return note.charAt(0).toUpperCase() + note.slice(1) + ' notes';
}
